  2→ * Next Actions focus management, empty state, and filter state
  3→ * -- progressive enhancement for HTMX.
  4→ *
  5→ * Focus management:
  6→ * After an HTMX complete or delete swap removes a next action item from the DOM,
  7→ * focus would otherwise be lost (sent to <body>). This script moves focus
  8→ * to the logical next element:
  9→ *   1. Next sibling next-action-item (if one exists)
 10→ *   2. Previous sibling next-action-item (if deleted was last in list)
 11→ *   3. The "Add next action" input (if the list is now empty)
 12→ *
 13→ * Inline edit focus:
 14→ * Entering edit mode focuses the edit input. Saving or canceling
 15→ * focuses the edit link on the restored item.
 16→ *
 17→ * Empty state transitions:
 18→ * When the last item is removed, shows the empty state message
 19→ * and hides the empty list. When items are added, hides the
 20→ * message and shows the list.
 21→ *
 22→ * Filter active state:
 23→ * When a filter link triggers an HTMX swap, updates aria-current
 24→ * and the active CSS class on the filter links.
 25→ *
 26→ * A11y: Focus management after DOM removal is required by WCAG 2.4.3
 27→ * (Focus Order) and is part of our HTMX Focus Management Protocol.
 28→ */
 29→(function () {
 30→  "use strict";
 31→
 32→  var pendingFocusTarget = null;
 33→  var pendingDeleteSwap = false;
 34→
 35→  document.body.addEventListener("htmx:beforeSwap", function (e) {
 36→    var target = e.detail.target;
 37→
 38→    if (!target || !target.classList || !target.classList.contains("next-action-item")) {
 39→      return;
 40→    }
 41→
 42→    var responseText = e.detail.xhr ? e.detail.xhr.responseText : "";
 43→
 44→    // Empty response = complete or delete operation (item removed)
 45→    if (responseText.trim() === "") {
 46→      pendingDeleteSwap = true;
 47→
 48→      var nextItem = target.nextElementSibling;
 49→      var prevItem = target.previousElementSibling;
 50→
 51→      if (nextItem && nextItem.classList.contains("next-action-item")) {
 52→        pendingFocusTarget = { type: "element", el: nextItem };
 53→      } else if (prevItem && prevItem.classList.contains("next-action-item")) {
 54→        pendingFocusTarget = { type: "element", el: prevItem };
 55→      } else {
 56→        pendingFocusTarget = { type: "element", el: document.getElementById("next-action-title") };
 57→      }
 58→      return;
